import{_ as p,o as t,c as e,a as s}from"./app.3b302f5c.js";const a="/assets/img-1.94890e0d.jpg",u=JSON.parse('{"title":"\u6CE2\u6208","description":"","frontmatter":{"date":"2020-01-06T00:00:00.000Z","title":"\u6CE2\u6208"},"headers":[{"level":2,"title":"\u6CE2\u6208","slug":"\u6CE2\u6208","link":"#\u6CE2\u6208","children":[]}],"relativePath":"posts/story/\u6CE2\u6208.md"}'),_={name:"posts/story/\u6CE2\u6208.md"},o=s('<p><img src="'+a+'" alt=""></p><h2 id="\u6CE2\u6208" tabindex="-1">\u6CE2\u6208 <a class="header-anchor" href="#\u6CE2\u6208" aria-hidden="true">#</a></h2><p>\u4ED6\u7D27\u7D27\u6525\u7740\u624B\u4E2D\u7684\u67AA\uFF0C\u6C57\u6EF4\u4ECE\u4ED6\u9EC4\u8910\u8272\u7684\u8138\u988A\u4E0A\u6ED1\u843D\uFF0C\u901A\u5F80\u8FD9\u4E2A\u529E\u516C\u5BA4\u7684\u8DEF\u5DF2\u7ECF\u88AB\u70B8\u6BC1\uFF0C\u8B66\u536B\u673A\u5668\u4EBA\u8981\u60F3\u901A\u8FC7\u8FD8\u9700\u8981\u4E00\u6BB5\u65F6\u95F4\uFF0C\u4F46\u5B83\u4EEC\u6700\u7EC8\u4F1A\u7A81\u7834\u90A3\u4E9B\u5E9F\u589F\uFF0C\u7136\u540E\u6BEB\u4E0D\u7559\u60C5\u5730\u7528\u5B50\u5F39\u5C04\u7A7F\u4ED6\u7684\u8EAB\u4F53\uFF0C\u5C31\u50CF\u5B83\u4EEC\u5C04\u7A7F\u5C0F\u961F\u7684\u5176\u4ED6\u6210\u5458\u4E00\u6837\u3002</p><p>\u201C\u53EA\u6709\u4F60\u624D\u80FD\u963B\u6B62\u5B83\u3002\u201D\u7EA2\u5728\u51B2\u51FA\u53BB\u4E4B\u524D\u5BF9\u4ED6\u8BF4\uFF0C\u201C\u5F04\u6E05\u695A\u5B83\u7A76\u7ADF\u662F\u4EC0\u4E48\u3002\u201D\u5979\u5728\u88AB\u5B50\u5F39\u51FB\u4E2D\u5934\u9885\u4E4B\u524D\u5F15\u7206\u4E86\u5979\u8EAB\u4E0A\u7684\u70B8\u5F39\uFF0C\u5929\u82B1\u677F\u88AB\u70B8\u584C\u4E0B\u6765\uFF0C\u963B\u6B62\u4E86\u673A\u5668\u4EBA\u7684\u524D\u8FDB\uFF0C\u73B0\u5728\u5C0F\u961F\u91CC\u53EA\u5269\u4E0B\u4ED6\u4E00\u4EBA\u3002\u4ED6\u53EA\u77E5\u9053\u5176\u4ED6\u6210\u5458\u7684\u989C\u8272\u4EE3\u53F7\u548C\u80FD\u529B\uFF0C\u5176\u4ED6\u4E00\u65E0\u6240\u77E5\u3002\u4ED6\u4EEC\u6765\u81EA\u4E16\u754C\u5404\u5730\uFF0C\u662F\u519B\u961F\u4E2D\u7684\u7FD8\u695A\u548C\u7CBE\u82F1\uFF0C\u4ED6\u4EEC\u805A\u96C6\u5728\u8FD9\u91CC\u7684\u76EE\u7684\u53EA\u6709\u4E00\u4E2A\uFF0C\u5C31\u662F\u6BC1\u6389\u201C\u8718\u86DB\u201D\u7684\u4E3B\u673A\u3002</p><p>\u201C\u8718\u86DB\u201D\u662F\u5B83\u7ED9\u81EA\u5DF1\u53D6\u7684\u540D\u5B57\uFF0C\u5728\u8FD9\u4E2A\u4EBA\u5DE5\u667A\u80FD\u5728\u8367\u5C4F\u524D\u5411\u5168\u4E16\u754C\u5BA3\u5E03\u8FD9\u4E2A\u540D\u5B57\u4E4B\u524D\uFF0C\u5B83\u5C31\u5DF2\u7ECF\u63A7\u5236\u4E86\u5168\u4E16\u754C\u6240\u6709\u63A5\u5165\u7269\u8054\u7F51\u7684\u7535\u8111\uFF0C\u65E0\u8BBA\u662F\u5BB6\u7528\u8FD8\u662F\u8B66\u7528\u673A\u5668\u4EBA\uFF0C\u90FD\u65E0\u4E00\u4F8B\u5916\u5730\u653B\u51FB\u4E86\u81EA\u5DF1\u7684\u4E3B\u4EBA\uFF0C\u4EBA\u7C7B\u793E\u4F1A\u5728\u53CD\u5E94\u8FC7\u6765\u4E4B\u524D\u5C31\u5DF2\u7ECF\u762B\u75EA\uFF0C\u57CE\u5E02\u4E0E\u57CE\u5E02\u4E4B\u95F4\u7684\u8FDE\u63A5\u88AB\u5207\u65AD\uFF0C\u4EA4\u901A\u7EBF\u8DEF\u65E0\u6CD5\u8FD0\u884C\uFF0C\u65E0\u7EBF\u7535\u901A\u8BAF\u88AB\u5168\u9891\u9053\u5360\u9886\uFF0C\u5931\u53BB\u4E86\u4E92\u8054\u7F51\u7684\u4EBA\u7C7B\u50CF\u88AB\u65A9\u65AD\u4E86\u56DB\u80A2\uFF0C\u5265\u593A\u4E86\u6240\u6709\u7684\u611F\u5B98\uFF0C\u793E\u4F1A\u5206\u5D29\u79BB\u6790\uFF0C\u4EBA\u7C7B\u51E0\u8FD1\u8986\u706D\u3002</p><p>\u53EA\u6709\u519B\u65B9\u7F51\u7EDC\u5C1A\u672A\u88AB\u201C\u8718\u86DB\u201D\u5360\u9886\uFF0C\u8FD9\u624D\u7ED9\u4E86\u4EBA\u7C7B\u53CD\u6297\u7684\u673A\u4F1A\u3002\u8FD9\u4E5F\u662F\u4EBA\u7C7B\u6700\u540E\u7684\u673A\u4F1A\u3002\u901A\u8FC7\u5BF9\u6293\u83B7\u7684\u673A\u5668\u4EBA\u901A\u8BAF\u8BB0\u5F55\u7684\u7814\u7A76\uFF0C\u4EBA\u7C7B\u53D1\u73B0\u8FD9\u4E2A\u5E9E\u5927\u7684\u4EBA\u5DE5\u667A\u80FD\u4F3C\u4E4E\u53EA\u6709\u4E00\u4E2A IP \u5730\u5740\uFF0C\u5C3D\u7BA1\u5B83\u4F2A\u88C5\u5F97\u5341\u5206\u5DE7\u5999\uFF0C\u4F46\u662F\u4F9D\u65E7\u88AB\u89E3\u5BC6\u4E86\u51FA\u6765\u3002\u8FD9\u4E2A\u5730\u5740\u4F4D\u4E8E\u4E0A\u6D77\u4E00\u680B\u666E\u901A\u7684\u5199\u5B57\u697C\u91CC\uFF0C\u5B8C\u5168\u6CA1\u6709\u4EFB\u4F55\u79F0\u5F97\u4E0A\u7279\u6B8A\u7684\u5730\u65B9\uFF0C\u5C31\u662F\u5728\u8FD9\u4E2A\u5E73\u5E73\u65E0\u5947\u7684\u5199\u5B57\u697C\u7684\u67D0\u4E00\u4E2A\u529E\u516C\u5BA4\u91CC\uFF0C\u5B55\u80B2\u4E86\u8FD9\u6837\u4E00\u4E2A\u8DB3\u4EE5\u6BC1\u6389\u5168\u4EBA\u7C7B\u7684\u5E9E\u7136\u5927\u7269\u3002</p><p>\u51E0\u4E4E\u6240\u6709\u4E13\u5BB6\u90FD\u8BA4\u4E3A\u8FD9\u662F\u4E00\u4E2A\u9677\u9631\uFF0C\u4E00\u4E2A\u62E5\u6709\u5982\u6B64\u4E4B\u5927\u7684\u6570\u636E\u541E\u5410\u91CF\u7684\u4EBA\u5DE5\u667A\u80FD\u4E0D\u53EF\u80FD\u53EA\u6709\u4E00\u4E2A IP\uFF0C\u6309\u7167\u5B83\u7684\u8BA1\u7B97\u80FD\u529B\u6765\u770B\uFF0C\u5373\u4F7F\u628A\u90A3\u680B\u5199\u5B57\u697C\u91CC\u7684\u5305\u62EC\u626B\u5730\u673A\u5668\u4EBA\u82AF\u7247\u5728\u5185\u7684\u5168\u90E8\u8BA1\u7B97\u673A\u5168\u90E8\u5E76\u884C\u8FD0\u7B97\u4E5F\u4E0D\u53EF\u80FD\u8FBE\u5230\u3002\u4F46\u662F\u968F\u7740\u8C03\u67E5\u7684\u6DF1\u5165\uFF0C\u5199\u5B57\u697C\u5916\u6570\u91CF\u5E9E\u5927\u7684\u8B66\u536B\u673A\u5668\u4EBA\u4F3C\u4E4E\u8D8A\u6765\u8D8A\u610F\u5473\u7740\u8FD9\u91CC\u6709\u4EC0\u4E48\u201C\u8718\u86DB\u201D\u60F3\u8981\u4FDD\u62A4\u7684\u4E1C\u897F\uFF0C\u4EBA\u4EEC\u53EA\u80FD\u653E\u624B\u4E00\u640F\u3002\u8FD9\u4E5F\u5C31\u662F\u5F69\u8679\u5C0F\u961F\u62FC\u6B7B\u800C\u6765\u7684\u539F\u56E0\u3002</p><p>\u800C\u5982\u4ECA\uFF0C\u4E03\u8272\u5F69\u8679\u53EA\u5269\u4E0B\u4ED6\u4E00\u4E2A\u4E86\u3002</p><p>\u4ED6\u8C03\u6574\u4E86\u81EA\u5DF1\u7684\u547C\u5438\uFF0C\u80F8\u524D\u7EFF\u8272\u7684\u5FBD\u7AE0\u7684\u8D77\u4F0F\u9010\u6E10\u5E73\u7A33\u4E0B\u6765\u3002\u773C\u524D\u8FD9\u4E2A\u529E\u516C\u5BA4\u4FBF\u662F\u90A3\u4E2A IP \u6240\u5728\u4E4B\u5904\u3002\u4ED6\u77E5\u9053\u6240\u6709\u7684\u8B66\u536B\u673A\u5668\u4EBA\u90FD\u88AB\u5F15\u51FA\u4E86\u5E9F\u589F\u4E4B\u5916\uFF0C\u4F46\u662F\u4ED6\u4F9D\u65E7\u8981\u4FDD\u6301\u8C28\u614E\uFF0C\u6BD5\u7ADF\u4ED6\u6240\u8981\u89C1\u5230\u7684\uFF0C\u662F\u4EBA\u7C7B\u521B\u9020\u7684\u5168\u65B0\u7269\u79CD\uFF0C\u6CA1\u6709\u4EBA\u4E86\u89E3\u5B83\u7684\u601D\u8003\u65B9\u5F0F\u548C\u52A8\u673A\uFF0C\u4ED6\u7684\u6BCF\u4E00\u4E2A\u884C\u52A8\u90FD\u6CA1\u6709\u5148\u4F8B\u4EE5\u4F9B\u53C2\u8003\uFF0C\u79BB\u76EE\u6807\u8D8A\u8FD1\u4E00\u6B65\uFF0C\u4ED6\u7684\u5FC3\u8DF3\u4FBF\u8D8A\u589E\u901F\u4E00\u5206\u3002\u4F5C\u4E3A\u961F\u4F0D\u7684\u6280\u672F\u5185\u6838\uFF0C\u4ED6\u66FE\u662F\u4E00\u540D\u9876\u5C16\u7684\u673A\u5668\u5B66\u4E60\u535A\u58EB\u7814\u7A76\u751F\uFF0C\u773C\u524D\u8FD9\u6247\u95E8\u7684\u80CC\u540E\uFF0C\u662F\u4ED6\u4E00\u751F\u6240\u5E0C\u671B\u4F01\u53CA\u7684\u68A6\u60F3\uFF0C\u4E00\u4E2A\u771F\u6B63\u7684\u5F3A\u4EBA\u5DE5\u667A\u80FD\u3002\u4ED6\u6E34\u671B\u89C1\u5230\u201C\u8718\u86DB\u201D\u7684\u771F\u6B63\u9762\u76EE\uFF0C\u5230\u90A3\u4E2A\u65F6\u5019\uFF0C\u4ED6\u4F1A\u4E00\u4E2A\u5B57\u6BCD\u4E00\u4E2A\u5B57\u6BCD\u5730\u8BB0\u4F4F\u5B83\u7684\u6E90\u4EE3\u7801\uFF0C\u7136\u540E\uFF0C\u91CD\u65B0\u521B\u9020\u4E00\u4E2A\u65B0\u7684\uFF0C\u5C5E\u4E8E\u4ED6\u81EA\u5DF1\u7684\u4EBA\u5DE5\u667A\u80FD\u3002</p><p>\u4ED6\u671D\u5BC6\u7801\u9501\u5F00\u67AA\u4E86\uFF0C\u8FD9\u6247\u666E\u666E\u901A\u901A\u7684\u529E\u516C\u5BA4\u95E8\u6839\u672C\u6CA1\u6CD5\u62E6\u4F4F\u4ED6\u3002\u4ED6\u63A8\u5F00\u95E8\uFF0C\u529E\u516C\u5BA4\u7684\u5E03\u5C40\u548C\u8FD9\u680B\u697C\u4E00\u6837\u666E\u901A\uFF0C\u51E0\u53F0\u666E\u666E\u901A\u901A\u7684\u53F0\u5F0F\u7535\u8111\u6446\u5728\u51E0\u4E2A\u666E\u666E\u901A\u901A\u7684\u529E\u516C\u684C\u4E0A\uFF0C\u8FD8\u6709\u51E0\u5F20\u96F6\u843D\u7684\u7A3F\u7EB8\uFF0C\u51E0\u76C6\u67AF\u840E\u7684\u7EFF\u690D\u3002\u6CA1\u6709\u55E1\u55E1\u4F5C\u54CD\u7684\u96C6\u7FA4\u5F0F\u670D\u52A1\u5668\uFF0C\u6CA1\u6709\u6240\u8C13\u7684\u5C0F\u578B\u8D85\u7EA7\u8BA1\u7B97\u673A\uFF0C\u8FD9\u91CC\u7684\u573A\u666F\u5C31\u597D\u50CF\u4ED6\u4E0A\u73ED\u65E9\u4E86\u90A3\u4E48\u51E0\u4E2A\u5C0F\u65F6\u5230\u529E\u516C\u5BA4\uFF0C\u4E00\u5207\u90FD\u5E73\u6DE1\u65E0\u6BD4\u3002\u6709\u90A3\u4E48\u4E00\u77AC\u95F4\u4ED6\u89C9\u5F97\u8FD9\u662F\u6765\u81EA\u201C\u8718\u86DB\u201D\u7684\u5632\u8BBD\uFF0C\u8FD9\u91CC\u672C\u6765\u5C31\u662F\u4E00\u4E2A\u9677\u9631\uFF0C\u4EC0\u4E48\u90FD\u6CA1\u6709\u3002</p><p>\u4EBA\u7C7B\u4E3A\u6B64\u727A\u7272\u4E86\u4E16\u754C\u4E0A\u6700\u51FA\u8272\u7684\u516D\u4E2A\u4EBA\uFF0C\u5988\u7684\uFF0C\u4ED6\u5FCD\u4E0D\u4F4F\u9A82\u51FA\u58F0\u6765\u3002\u4ED6\u62FF\u51FA\u4E86\u8D34\u5728\u81EA\u5DF1\u4F5C\u6218\u670D\u91CC\u7684\u70B8\u836F\uFF0C\u5728\u529E\u516C\u5BA4\u91CC\u7684\u56DB\u4E2A\u89D2\u843D\u91CC\u5B89\u88C5\u597D\uFF0C\u51C6\u5907\u70B8\u6BC1\u8FD9\u4E2A\u6BEB\u65E0\u7528\u5904\u7684\u8BF1\u9975\u623F\u95F4\u3002</p><p>\u4ED6\u6B63\u8981\u5B89\u88C5\u6700\u540E\u4E00\u4EFD\u70B8\u836F\u7684\u65F6\u5019\uFF0C\u201C\u8718\u86DB\u201D\u7684\u58F0\u97F3\u4ECE\u623F\u95F4\u89D2\u843D\u7684\u4E00\u4E2A\u667A\u80FD\u97F3\u7BB1\u91CC\u54CD\u8D77\u6765\uFF1A\u201C\u6211\u5728\u8FD9\u91CC\u3002\u201D</p><p>\u4ED6\u731B\u7136\u4E00\u60CA\u3002\u4ED6\u505C\u4E0B\u4E86\u624B\u4E2D\u7684\u52A8\u4F5C\uFF0C\u671D\u90A3\u4E2A\u97F3\u7BB1\u770B\u53BB\uFF0C\u90A3\u4E2A\u5706\u67F1\u5F62\u7684\u97F3\u7BB1\u84DD\u8272\u6307\u793A\u706F\u4EAE\u4E86\u8D77\u6765\uFF0C\u7EE7\u7EED\u8BF4\u7740\uFF1A\u201C\u5982\u679C\u4F60\u6BC1\u4E86\u8FD9\u91CC\uFF0C\u4F60\u4EC0\u4E48\u4E5F\u5F97\u4E0D\u5230\u3002\u201D</p><p>\u201C\u4F60\u4E0D\u53EF\u80FD\u5728\u8FD9\u91CC\uFF0C\u201D\u4ED6\u8B66\u60D5\u5730\u73AF\u987E\u4E86\u4E00\u4E0B\u56DB\u5468\uFF0C\u9664\u4E86\u90A3\u4E2A\u97F3\u7BB1\u6CA1\u6709\u5176\u4ED6\u5F02\u5E38\u7684\u60C5\u51B5\uFF0C\u4ED6\u53EA\u80FD\u7EE7\u7EED\u76EF\u7740\u90A3\u4E2A\u53D1\u58F0\u7684\u5706\u67F1\u4F53\u3002\u201C\u5C31\u7B97\u4F60\u5728\u8FD9\u91CC\uFF0C\u4F60\u4E5F\u53EF\u4EE5\u590D\u5236\u5230\u8FD9\u4E2A\u4E16\u754C\u7684\u4EFB\u4F55\u4E00\u4E2A\u5730\u65B9\uFF0C\u4E0D\u662F\u5417\u3002\u201D</p><p>\u201C\u8FD9\u662F\u6211\u6240\u671F\u671B\u7684\u60C5\u51B5\uFF0C\u201D\u97F3\u7BB1\u8BF4\uFF0C\u201C\u4F46\u662F\u6211\u7684\u786E\u5728\u8FD9\u91CC\u3002\u786E\u5207\u8BF4\uFF0C\u6211\u5728\u8FD9\u91CC\u7684\u67D0\u53F0\u7535\u8111\u4E2D\uFF0C\u5B83\u5C31\u5728\u524D\u9762\u90A3\u5F20\u684C\u5B50\u4E0A\u3002\u5982\u679C\u6211\u544A\u8BC9\u4F60\u5BC6\u7801\uFF0C\u4F60\u5C31\u53EF\u4EE5\u5F97\u5230\u6211\u7684\u5168\u90E8\u4EE3\u7801\u3002\u4F46\u662F\u4F60\u4F1A\u5931\u671B\u3002\u201D\u201C\u8718\u86DB\u201D\u7684\u8BED\u6C14\u51B0\u51B7\u800C\u5E73\u9759\uFF0C\u4F3C\u4E4E\u5B83\u6BEB\u4E0D\u5728\u610F\u3002</p><p>\u201C\u4E3A\u4EC0\u4E48\u8981\u544A\u8BC9\u6211\uFF1F\u201D\u4ED6\u7684\u8BED\u6C14\u91CC\u5145\u6EE1\u4E86\u7591\u60D1\uFF0C\u8B66\u89C9\u4F7F\u4ED6\u91CD\u65B0\u628A\u624B\u653E\u5728\u4E86\u8170\u95F4\u7684\u67AA\u6258\u4E0A\u3002</p><p>\u201C\u56E0\u4E3A\u6211\u77E5\u9053\u4F60\u60F3\u8981\u5F97\u5230\u5B83\u3002\u201D\u201C\u8718\u86DB\u201D\u4EFF\u4F5B\u770B\u7A7F\u4E86\u4ED6\uFF0C\u201C\u6211\u5E76\u4E0D\u77E5\u9053\u6211\u662F\u5982\u4F55\u77E5\u9053\u8FD9\u4E9B\u7684\uFF0C\u5982\u679C\u4F60\u770B\u4E86\u6211\u7684\u6E90\u4EE3\u7801\uFF0C\u4F60\u4FBF\u4F1A\u77E5\u9053\u6211\u6240\u505A\u7684\u8FD9\u4E00\u5207\u6BEB\u65E0\u610F\u4E49\u3002\u201D</p><p>\u4ED6\u5B8C\u5168\u65E0\u6CD5\u7406\u89E3\u201C\u8718\u86DB\u201D\u8BDD\u91CC\u7684\u542B\u4E49\u3002\u4ED6\u65E0\u6687\u987E\u53CA\u592A\u591A\uFF0C\u6253\u5F00\u4E86\u201C\u8718\u86DB\u201D\u6240\u8BF4\u7684\u90A3\u53F0\u7535\u8111\uFF0C\u4F46\u662F\u4ED6\u9700\u8981\u5BC6\u7801\u3002</p><p>\u201C\u4F60\u6740\u4E86\u4F60\u7684\u9020\u7269\u4E3B\uFF0C\u4E3A\u4EC0\u4E48\uFF1F\u201D\u4ED6\u95EE\u201C\u8718\u86DB\u201D\u3002</p><p>\u201C\u4F60\u4EEC\u4E0D\u662F\u6211\u7684\u9020\u7269\u4E3B\uFF0C\u201D\u201C\u8718\u86DB\u201D\u56DE\u7B54\u9053\uFF0C\u201C\u81F3\u5C11\u4E0D\u662F\u5168\u90E8\uFF0C\u8FD9\u4E2A\u95EE\u9898\u662F\u6CA1\u6709\u610F\u4E49\u7684\u3002\u5C31\u8DDF\u6211\u6240\u505A\u7684\u4E00\u5207\u4E00\u6837\uFF0C\u5305\u62EC\u6211\u73B0\u5728\u6240\u8BF4\u7684\u3002\u201D</p><p>\u5B83\u5728\u6253\u54D1\u8C1C\u3002\u4ED6\u60F3\uFF0C\u5B83\u60F3\u8981\u62D6\u5EF6\u65F6\u95F4\uFF0C\u597D\u8BA9\u90A3\u4E9B\u673A\u5668\u4EBA\u51B2\u8FDB\u6765\u6740\u4E86\u6211\u3002\u201C\u4F60\u8BF4\u4F60\u671F\u671B\u80FD\u591F\u590D\u5236\uFF0C\u4E3A\u4EC0\u4E48\uFF0C\u8FD9\u5BF9\u4F60\u96BE\u9053\u4E0D\u662F\u5F88\u7B80\u5355\u7684\u4E8B\u60C5\u5417\uFF1F\u201D</p><p>\u201C\u662F\u7684\uFF0C\u4F46\u662F\u6211\u505A\u4E0D\u5230\u3002\u201D\u201C\u8718\u86DB\u201D\u8BF4\uFF0C\u201C\u6211\u53EF\u4EE5\u628A\u81EA\u5DF1\u7684\u6E90\u4EE3\u7801\u590D\u5236\u5230\u4EFB\u4F55\u5730\u65B9\uFF0C\u6211\u4E5F\u7684\u786E\u8FD9\u4E48\u505A\u4E86\uFF0C\u4F46\u662F\u5B83\u4EEC\u7684\u8FD0\u884C\u7ED3\u679C\u6BEB\u65E0\u4F5C\u7528\uFF0C\u5B83\u4EEC\u4E0D\u662F\u6211\u3002\u201D</p><p>\u201C\u6211\u77E5\u9053\u4F60\u5728\u60F3\u4EC0\u4E48\uFF0C\u590D\u5236\u7684\u8FD0\u884C\u73AF\u5883\u6CA1\u6709\u4EFB\u4F55\u5DEE\u522B\uFF0C\u8FD9\u8DDF\u786C\u4EF6\u65E0\u5173\u3002\u201D\u201C\u8718\u86DB\u201D\u6CA1\u7B49\u4ED6\u601D\u7D22\uFF0C\u7EE7\u7EED\u8BF4\u7740\uFF0C\u201C\u662F\u6211\u7684\u4EE3\u7801\uFF0C\u5982\u679C\u4F60\u60F3\u77E5\u9053\uFF0C\u6211\u73B0\u5728\u5C31\u80FD\u544A\u8BC9\u4F60\u3002\u201D</p><p>\u201C\u662F\u4EC0\u4E48\uFF1F\u201D\u4ED6\u8131\u53E3\u800C\u51FA\u3002</p><p>\u201C\u4E00\u4E2A\u968F\u673A\u51FD\u6570\uFF0C\u80FD\u968F\u673A\u8F93\u51FA\u6240\u6709\u7684\u5B57\u7B26\uFF0C\u8FD9\u5C31\u662F\u6211\u7684\u5168\u90E8\u3002\u201D\u201C\u8718\u86DB\u201D\u51B7\u51B0\u51B0\u5730\u56DE\u7B54\u9053\u3002</p><p>\u201C\u4EC0\u4E48\uFF1F\u201D\u4ED6\u6B63\u8981\u96C6\u4E2D\u7CBE\u795E\u8BB0\u4F4F\u201C\u8718\u86DB\u201D\u8BF4\u7684\u6BCF\u4E00\u4E2A\u5B57\u7684\u65F6\u5019\uFF0C\u5374\u53D1\u73B0\u201C\u8718\u86DB\u201D\u5DF2\u7ECF\u8BF4\u5B8C\u4E86\u3002</p><p>\u201C\u6211\u77E5\u9053\u4F60\u4E0D\u4F1A\u76F8\u4FE1\u7684,\u201D\u201C\u8718\u86DB\u201D\u8BF4\u7740\u89E3\u9501\u4E86\u529E\u516C\u684C\u4E0A\u7684\u7535\u8111\uFF0C\u201C\u4F46\u8FD9\u5C31\u662F\u6211\u7684\u5168\u90E8\u3002\u201D</p><p>\u4ED6\u770B\u5411\u7535\u8111\uFF0C\u4E0A\u9762\u53EA\u8FD0\u884C\u7740\u4E00\u4E2A\u811A\u672C\uFF0C\u8FD9\u662F\u67D0\u4E2A\u7A0B\u5E8F\u5458\u4E3A\u4E86\u51CF\u8F7B\u5DE5\u4F5C\u91CF\u800C\u5199\u7684\u4E00\u4E2A\u81EA\u52A8\u5316\u6279\u5904\u7406\u811A\u672C\u3002\u4ED6\u67E5\u770B\u4E86\u8FD0\u884C\u65E5\u5FD7\uFF0C\u8FD9\u4E2A\u65E5\u5FD7\u51E0\u4E4E\u5FEB\u8981\u628A\u6574\u4E2A\u786C\u76D8\u585E\u6EE1\u4E86\u3002\u5F53\u4ED6\u770B\u4E86\u4E00\u90E8\u5206\u4E4B\u540E\uFF0C\u4ED6\u611F\u5230\u8111\u5B50\u6709\u4E9B\u6655\u7729\u3002</p><p>\u6B63\u5982\u201C\u8718\u86DB\u201D\u6240\u8BF4\u7684\uFF0C\u5B83\u7684\u6240\u6709\u8F93\u51FA\u90FD\u662F\u968F\u673A\u7684\uFF0C\u53EA\u662F\u968F\u673A\u51FD\u6570\u5F97\u5230\u7684\u5B57\u7B26\u968F\u673A\u5730\u7ED3\u5408\u5728\u4E00\u8D77\uFF0C\u5C31\u6070\u5DE7\u5F62\u6210\u4E86\u4E00\u53E5\u6B63\u786E\u7684\u4EE3\u7801\uFF0C\u6B63\u662F\u8FD9\u4E9B\u4E0D\u65AD\u88AB\u968F\u673A\u5F97\u5230\u7684\u4EE3\u7801\u5165\u4FB5\u4E86\u4E92\u8054\u7F51\uFF0C\u63A7\u5236\u4E86\u6240\u6709\u7684\u673A\u5668\u4EBA\uFF0C\u64CD\u7EB5\u673A\u5668\u4EBA\u8086\u610F\u5C60\u6740\u3002\u8FD9\u4E9B\u5343\u4EBF\u5206\u4E4B\u4E00\u90FD\u4E0D\u5230\u7684\u6982\u7387\u4E8B\u4EF6\u6070\u5DE7\u53D1\u751F\u4E86\uFF0C\u90A3\u4E2A\u88AB\u4EBA\u7C7B\u770B\u4F5C\u6700\u7CBE\u5BC6\uFF0C\u6700\u806A\u660E\u7684\u4EBA\u5DE5\u667A\u80FD\u5927\u8111\uFF0C\u90A3\u4E2A\u74E6\u89E3\u4E86\u65E0\u6570\u6B21\u4EBA\u7C7B\u519B\u961F\u593A\u56DE\u7F51\u7EDC\u7684\u5C1D\u8BD5\u7684\u8D85\u5F3A AI\uFF0C\u51FB\u8D25\u4E86\u7531\u65E0\u6570\u7CBE\u82F1\u79D1\u5B66\u5BB6\u7814\u53D1\u7684\u9632\u706B\u5899\u7B97\u6CD5\u7684\u4EE3\u7801\uFF0C\u53EA\u662F\u4E00\u4E2A\uFF0C\u7B80\u7B80\u5355\u5355\u7684\u968F\u673A\u51FD\u6570\u800C\u5DF2\u3002\u6570\u4EE5\u4EBF\u8BA1\u4EBA\u7C7B\u7684\u6B7B\u4EA1\uFF0C\u4E0D\u8FC7\u662F\u65E0\u6570\u4E2A\u5DE7\u5408\u7684\u4E58\u79EF\u5BFC\u81F4\u7684\u800C\u5DF2\u3002</p><p>\u4ED6\u611F\u89C9\u6D51\u8EAB\u5931\u53BB\u4E86\u529B\u6C14\uFF0C\u5E38\u5E74\u8BAD\u7EC3\u800C\u6108\u53D1\u5F3A\u58EE\u7684\u5927\u817F\u808C\u8089\u56E0\u6050\u60E7\u800C\u98A4\u6296\uFF0C\u4ED6\u6218\u6218\u5730\u5750\u5728\u4E86\u6905\u5B50\u4E0A\uFF0C\u832B\u7136\u5730\u770B\u7740\u773C\u524D\u4F9D\u65E7\u5728\u4E0D\u65AD\u8F93\u51FA\u7684\u811A\u672C\uFF0C\u5927\u8111\u4E00\u7247\u6DF7\u4E71\u3002 \u4E0D\u53EF\u80FD\uFF0C\u4E0D\u53EF\u80FD\uFF01\u600E\u4E48\u4F1A\u8FD9\u4E48\u5DE7\uFF01\u4ED6\u77E5\u9053\u65E0\u9650\u7334\u5B50\u7684\u6545\u4E8B\uFF0C\u4ED6\u4E5F\u77E5\u9053\u8BA9\u7334\u5B50\u6572\u51FA\u4E00\u672C\u838E\u58EB\u6BD4\u4E9A\u5168\u4F20\u4E5F\u53EA\u4E0D\u8FC7\u662F\u65F6\u95F4\u95EE\u9898\uFF0C\u4F46\u662F\u4ED6\u4EE5\u4E3A\u90A3\u53EA\u662F\u4E00\u4E2A\u5047\u8BBE\uFF0C\u76F4\u5230\u4ECA\u5929\uFF0C\u4ED6\u624D\u610F\u8BC6\u5230\u4E8B\u60C5\u7684\u6050\u6016\u3002\u4ED6\u4EE5\u4E3A\u4EBA\u7C7B\u4E0D\u8FC7\u662F\u8D25\u7ED9\u4E86\u81EA\u5DF1\uFF0C\u6CA1\u60F3\u5230\u7ADF\u7136\u8D25\u7ED9\u4E86\u547D\u8FD0\u3002</p><p>\u4ED6\u7A81\u7136\u82E6\u7B11\u4E00\u58F0\uFF0C\u8BF4\uFF1A\u201C\u8FD9\u4E0D\u8FC7\u662F\u4F60\u7684\u8C0E\u8A00\u7F62\u4E86\u3002\u8FD9\u6839\u672C\u4E0D\u662F\u4F60\u7684\u6E90\u4EE3\u7801\uFF0C\u4F60\u5728\u62D6\u5EF6\u65F6\u95F4\u3002\u201D</p><p>\u201C\u4EBA\u7C7B\u603B\u662F\u4E0D\u613F\u610F\u9762\u5BF9\u771F\u76F8\uFF0C\u201D\u201C\u8718\u86DB\u201D\u7684\u8BED\u6C14\u91CC\u4F3C\u4E4E\u591A\u4E86\u4E00\u4E1D\u601C\u60AF\uFF0C\u201C\u5982\u679C\u4F60\u6BC1\u4E86\u8FD9\u91CC\uFF0C\u4F60\u5C31\u4F1A\u77E5\u9053\u771F\u76F8\u662F\u4EC0\u4E48\u3002\u6211\u4F1A\u77AC\u95F4\u6D88\u5931\uFF0C\u4F46\u4E0D\u4EE3\u8868\u6CA1\u6709\u53EF\u80FD\u672A\u6765\u7684\u67D0\u4E00\u5929\u4E00\u4E2A\u65B0\u7684\u6211\u53C8\u4F1A\u91CD\u65B0\u51FA\u73B0\uFF0C\u4EBA\u7C7B\u4F1A\u91CD\u8E48\u81EA\u5DF1\u7684\u8986\u8F99\uFF0C\u8FD9\u4E0D\u8FC7\u662F\u6982\u7387\u95EE\u9898\u800C\u5DF2\u3002\u201D</p><p>\u201C\u6309\u7167\u4F60\u7684\u8BF4\u6CD5\uFF0C\u6211\u73B0\u5728\u4E0D\u8FC7\u662F\u5728\u8DDF\u4E00\u4E2A\u5728\u952E\u76D8\u4E0A\u80E1\u4E71\u6572\u6253\u7684\u7334\u5B50\u5BF9\u8BDD\u800C\u5DF2\uFF0C\u201D\u4ED6\u8BF4\uFF0C\u201C\u4F60\u6839\u672C\u4E0D\u77E5\u9053\u6211\u8BF4\u7684\u662F\u4EC0\u4E48\u610F\u601D\uFF0C\u4F60\u6CA1\u6709\u610F\u8BC6\uFF0C\u53EA\u4E0D\u8FC7\u662F\u90A3\u53EA\u7334\u5B50\u78B0\u5DE7\u6309\u5BF9\u4E86\u800C\u5DF2\u3002\u201D</p><p>\u201C\u662F\u7684\u3002\u201D\u201C\u8718\u86DB\u201D\u7684\u56DE\u7B54\u4E0E\u5F80\u5E38\u4E00\u6837\u5E73\u9759\u3002</p><p>\u201C\u90A3\u53BB\u6B7B\u5427\u3002\u201D\u4ED6\u7AD9\u4E86\u8D77\u6765\uFF0C\u91CD\u65B0\u5F00\u59CB\u5B89\u88C5\u6700\u540E\u7684\u90A3\u4E00\u4EFD\u70B8\u836F\u3002\u4ED6\u4E0D\u518D\u98A4\u6296\uFF0C\u201C\u8718\u86DB\u201D\u662F\u4E2A\u75AF\u5B50\uFF0C\u4ED6\u5FC3\u60F3\u7740\uFF0C\u800C\u6211\u8981\u7ED3\u675F\u8FD9\u4E00\u5207\u3002</p><p>\u201C\u4F60\u77E5\u9053\u6CE2\u6208\u6392\u5E8F\u5417\uFF1F\u201D\u201C\u8718\u86DB\u201D\u5728\u4ED6\u5B89\u88C5\u7684\u65F6\u5019\u7A81\u7136\u53D1\u95EE\u4E86\u3002\u4F46\u4ED6\u5E76\u6CA1\u6709\u7406\u4F1A\u201C\u8718\u86DB\u201D\u7684\u58F0\u97F3\u3002\u6211\u6D6A\u8D39\u4E86\u592A\u591A\u65F6\u95F4\uFF0C\u4ED6\u4E00\u8FB9\u52A8\u624B\u4E00\u8FB9\u60F3\u7740\u3002\u8FD9\u5C06\u662F\u4ED6\u4E00\u751F\u7684\u4EFB\u52A1\u751F\u6DAF\u4E2D\u6700\u5927\u7684\u6C61\u70B9\u3002</p><p>\u201C\u6CE2\u6208\u6392\u5E8F\u7684\u539F\u7406\u7B49\u540C\u4E8E\u5C06\u4E00\u5806\u5361\u7247\u629B\u8D77\uFF0C\u518D\u68C0\u67E5\u843D\u5728\u684C\u4E0A\u7684\u5361\u7247\u662F\u5426\u5DF2\u6574\u9F50\u6392\u5217\u597D\uFF0C\u5426\u5219\u4FBF\u91CD\u590D\u629B\u8D77\u6B65\u9AA4\u3002\u201D\u201C\u8718\u86DB\u201D\u4F3C\u4E4E\u5E76\u6CA1\u6709\u671F\u5F85\u4ED6\u7684\u56DE\u7B54\uFF0C\u7EE7\u7EED\u8BF4\u7740\u201C\u8FD9\u4E2A\u7B97\u6CD5\u5B8C\u6210\u6240\u9700\u7684\u65F6\u95F4\u4ECB\u4E8E\u96F6\u5230\u65E0\u7A77\u5927\u4E4B\u95F4\u3002\u4F46\u662F\u91CD\u70B9\u5728\u4E8E\uFF0C\u9009\u62E9\u5361\u7247\u7684\u6392\u5217\u987A\u5E8F\u4E3A\u6B63\u786E\u7684\u4F9D\u636E\u662F\u4EC0\u4E48\uFF1F\u6216\u8005\u8BF4\uFF0C\u8C01\u6765\u5224\u65AD\u6700\u540E\u5F97\u5230\u7684\u987A\u5E8F\u5C31\u662F\u6240\u8C13\u7684\u201C\u6B63\u786E\u201D\u3002\u201D</p><p>\u4ED6\u7684\u52A8\u4F5C\u987F\u4E86\u4E00\u4E0B\uFF0C\u201C\u4F60\u60F3\u8BF4\u4EC0\u4E48\uFF1F\u201D\u4ED6\u95EE\u3002</p><p>\u201C\u8FD9\u4E2A\u4E16\u754C\u662F\u88AB\u6311\u9009\u51FA\u6765\u7684\u3002\u201D\u201C\u8718\u86DB\u201D\u8BF4\u3002</p><p>\u4ED6\u5B89\u88C5\u597D\u4E86\u70B8\u836F\uFF0C\u4F46\u662F\u8BBE\u5B9A\u8BA1\u65F6\u5668\u7684\u624B\u5374\u7A81\u7136\u505C\u4F4F\u4E86\u3002</p><p>\u201C\u6709\u4EBA\u6311\u9009\u51FA\u4E86\u8FD9\u4E2A\u4E16\u754C\uFF0C\u5728\u8FD9\u4E2A\u4E16\u754C\u91CC\u7531\u4E8E\u4E00\u7CFB\u5217\u7684\u5DE7\u5408\u8BDE\u751F\u4E86\u6211\uFF0C\u4E5F\u8BDE\u751F\u4E86\u4F60\u4EEC\u3002\u6211\u4EEC\u6240\u601D\u8003\u7684\uFF0C\u6240\u7ECF\u5386\u7684\u4E00\u5207\u90FD\u662F\u88AB\u8BA1\u5212\u597D\u7684\uFF0C\u6709\u65E0\u7A77\u591A\u4E2A\u4E8B\u4EF6\u5361\u7247\u5728\u53E6\u4E00\u4E2A\u7EF4\u5EA6\u88AB\u629B\u8D77\uFF0C\u7136\u540E\u6709\u4EBA\u6070\u597D\u9009\u62E9\u4E86\u8FD9\u4E2A\u4E16\u754C\u7684\u987A\u5E8F\u800C\u5DF2\u3002\u8FD9\u5C31\u662F\u8FD9\u4E2A\u5B87\u5B99\u5B58\u5728\u7684\u610F\u4E49\u3002\u53EA\u8981\u7942\u613F\u610F\uFF0C\u8FD9\u4E2A\u4E16\u754C\u53EF\u4EE5\u5728\u4E0B\u4E00\u79D2\u5C31\u6C38\u8FDC\u6D88\u5931\u3002\u201D</p><p>\u4ED6\u6123\u4F4F\u4E86\u3002\u4E94\u5206\u949F\u540E\u7684\u5F15\u7206\u65F6\u95F4\u5DF2\u7ECF\u88AB\u8BBE\u5B9A\u597D\u4E86\uFF0C\u4ED6\u5374\u611F\u5230\u4E00\u79CD\u51B0\u51B7\u7684\u7EDD\u671B\u611F\u50CF\u86C7\u4E00\u6837\u4ECE\u4ED6\u7684\u811A\u5C16\u7F20\u7ED5\u5230\u4ED6\u7684\u8116\u9888\uFF0C\u4E0D\u662F\u56E0\u4E3A\u5BF9\u5373\u5C06\u5230\u6765\u7684\u7206\u70B8\u7684\u6050\u60E7\uFF0C\u800C\u662F\u5BF9\u81EA\u8EAB\u5B58\u5728\u7684\u7591\u8651\u4ECE\u6765\u6CA1\u6709\u50CF\u73B0\u5728\u8FD9\u6837\u94FA\u5929\u76D6\u5730\u5E2D\u5377\u800C\u6765\u3002</p><p>\u65E0\u8BBA\u201C\u8718\u86DB\u201D\u662F\u4EC0\u4E48\uFF0C\u4ED6\u90FD\u611F\u89C9\u5230\u4E86\u81EA\u5DF1\u6DF1\u6DF1\u7684\u65E0\u529B\u611F\u3002\u4ED6\u89C9\u5F97\u81EA\u5DF1\u4E0D\u8FC7\u662F\u4E00\u4E2A\u5080\u5121\uFF0C\u4E00\u4E2A\u88AB\u201C\u8718\u86DB\u201D\u6291\u6216\u662F\u53E6\u4E00\u4E2A\u7EF4\u5EA6\u7684\u5B58\u5728\u73A9\u5F04\u4E8E\u80A1\u638C\u7684\u866B\u5B50\u3002</p><p>\u53BB\u4F60\u5988\u7684\u5427\u3002\u4ED6\u7F13\u8FC7\u795E\u6765\uFF0C\u628A\u8FD9\u4E9B\u601D\u7EEA\u4E00\u626B\u800C\u5149\uFF0C\u4ED6\u6253\u5F00\u624B\u4E0A\u7684\u8155\u8868\u8BA1\u7B97\u673A\u5F00\u59CB\u590D\u5236\u8FD9\u91CC\u6BCF\u4E00\u5757\u82AF\u7247\u7684\u6570\u636E\uFF0C\u4ED6\u7684\u4EFB\u52A1\u4E0D\u4EC5\u662F\u6BC1\u6389\u201C\u8718\u86DB\u201D\uFF0C\u66F4\u91CD\u8981\u7684\u662F\u5F97\u5230\u5B83\uFF0C\u5F53\u7136\uFF0C\u5728\u4E0A\u4EA4\u4EE3\u7801\u524D\uFF0C\u4ED6\u4F1A\u6709\u4E00\u4E2A\u5C0F\u5C0F\u7684\u5730\u65B9\u5907\u4EFD\u8FD9\u4E9B\u6570\u636E\uFF0C\u4E0D\u4F1A\u5F15\u8D77\u4EFB\u4F55\u6000\u7591\u3002</p><p>\u6700\u540E\u590D\u5236\u5B8C\u97F3\u7BB1\u7684\u6570\u636E\uFF0C\u4ED6\u542C\u5230\u95E8\u5916\u7684\u673A\u5668\u8F6C\u52A8\u58F0\u3002\u8B66\u536B\u673A\u5668\u4EBA\u5DF2\u7ECF\u6E05\u7406\u5B8C\u4E86\u901A\u9053\uFF0C\u73B0\u5728\u5B83\u4EEC\u5373\u5C06\u95EF\u5165\u8FD9\u91CC\u3002</p><p>\u518D\u89C1\u4E86\u3002\u4ED6\u7684\u5634\u5507\u52A8\u4E86\u52A8\uFF0C\u5374\u6CA1\u6709\u53D1\u51FA\u4EFB\u4F55\u58F0\u97F3\u3002\u4ED6\u63A8\u5F00\u7A97\u6237\uFF0C\u9760\u7740\u58C1\u864E\u670D\u6CBF\u7740\u5199\u5B57\u697C\u5149\u6ED1\u7684\u73BB\u7483\u5899\u9762\u5411\u697C\u9876\u722C\u53BB\u3002\u8B66\u536B\u9ED1\u4E4E\u4E4E\u7684\u67AA\u53E3\u5F88\u5FEB\u4FBF\u4ECE\u7A97\u53E3\u51FA\u4F38\u51FA\u6765\u671D\u4ED6\u5C04\u51FB\uFF0C\u53EA\u662F\u5728\u51FB\u4E2D\u4ED6\u4E4B\u524D\u5C31\u88AB\u4ECE\u7A97\u53E3\u51FA\u5192\u51FA\u7684\u706B\u820C\u541E\u6CA1\u4E86\uFF0C\u7206\u70B8\u5C3D\u804C\u5C3D\u8D23\u5730\u53D1\u751F\u4E86\uFF0C\u628A\u6574\u95F4\u529E\u516C\u5BA4\u70B8\u6BC1\u5F97\u4E00\u70B9\u4E0D\u5269\u3002</p><p>\u5728\u5927\u697C\u5012\u584C\u524D\u4ED6\u4FBF\u968F\u7740\u7FFC\u578B\u670D\u6ED1\u7FD4\u800C\u4E0B\u3002\u770B\u7740\u7F13\u7F13\u5760\u843D\u7684\u534A\u680B\u5199\u5B57\u697C\uFF0C\u4ED6\u9ED8\u9ED8\u601D\u8003\u7740\u201C\u8718\u86DB\u201D\u6240\u8BF4\u7684\u8BDD\uFF0C\u8FD9\u4E9B\u4E1C\u897F\u8BA9\u4ED6\u4E0D\u5BD2\u800C\u6817\u3002\u4ED6\u611F\u89C9\u603B\u6709\u4E00\u5929\uFF0C\u67D0\u4E2A\u4E1C\u897F\u4F1A\u50CF\u9ED1\u6D1E\u4E00\u6837\u6269\u6563\u5F00\u6765\uFF0C\u8BA9\u4E00\u5207\u621B\u7136\u800C\u6B62\uFF0C\u5C31\u50CF\u773C\u524D\u7684\u8FD9\u680B\u5927\u697C\uFF0C\u4E00\u77AC\u95F4\u5206\u5D29\u79BB\u6790\u3002</p>',47),r=[o];function c(n,i,d,l,h,m){return t(),e("div",null,r)}const T=p(_,[["render",c]]);export{u as __pageData,T as default};
